// Reads query params from the webhook.
// Required: customer_id
// Optional: supplier_id, limit, product_id
//
// Single-product push (from product detail page):
//   GET /webhook/ops-push?customer_id=<uuid>&product_id=<uuid>&limit=1
//
// Bulk push (all products for a customer/supplier):
//   GET /webhook/ops-push?customer_id=<uuid>&supplier_id=<uuid>&limit=25

const first = $input.first().json ?? {};
const q = first.query ?? first.queryParameters ?? {};

const customer_id = q.customer_id ?? q.customerId;
if (!customer_id) {
  throw new Error('Missing required query param: customer_id');
}

const supplier_id = q.supplier_id ?? q.supplierId ?? null;
const product_id = q.product_id ?? q.productId ?? null;
const limitRaw = q.limit ?? 25;
const limit = Math.max(1, Math.min(200, Number(limitRaw) || 25));

const api_base = $env.API_HUB_BASE_URL || 'http://host.docker.internal:8000';

// When product_id is provided, fetch that one product directly.
// Otherwise, fetch the full product list (bulk push).
let products_url;
if (product_id) {
  products_url = `${api_base.replace(/\/$/, '')}/api/products/${product_id}`;
} else {
  const url = new URL(`${api_base.replace(/\/$/, '')}/api/products`);
  url.searchParams.set('limit', String(limit));
  if (supplier_id) url.searchParams.set('supplier_id', String(supplier_id));
  products_url = url.toString();
}

return [{
  json: {
    api_base,
    customer_id: String(customer_id),
    supplier_id: supplier_id ? String(supplier_id) : null,
    product_id: product_id ? String(product_id) : null,
    limit,
    products_url,
  },
}];

// Normalize the /api/products response into one item per product.

const ctx = $node['Parse Params'].json;
const items = $input.all();

const list = items.flatMap((i) => {
  const j = i.json;
  if (Array.isArray(j)) return j;
  if (j && Array.isArray(j.data)) return j.data;
  if (j && Array.isArray(j.body)) return j.body;
  return j && typeof j === 'object' ? [j] : [];
});

return list
  .filter((p) => p && (p.id || p.product_id))
  .map((p) => ({
    json: {
      api_base: ctx.api_base,
      customer_id: ctx.customer_id,
      product_id: String(p.id ?? p.product_id),
      product_name: p.product_name ?? p.name ?? p.products_title ?? 'Unnamed',
      supplier_name: p.supplier_name ?? null,
    },
  }));

// Builds JSON-string inputs for OPS setProductCategory + setProduct + setProductPrice.
//
// setProductCategory_input: category is created first; the returned category_id is
// injected into setProduct_input by the downstream 'Attach Category ID' node.

const items = $input.all();

function minNumber(values) {
  const nums = values.filter((v) => typeof v === 'number' && Number.isFinite(v));
  if (!nums.length) return null;
  return Math.min(...nums);
}

return items.map((item) => {
  const merged = item.json ?? {};
  const payload = merged.product ? merged : (merged.payload ?? merged);

  const productMeta = payload.product ?? {};
  const variants = Array.isArray(payload.variants) ? payload.variants : [];

  const minFinal = minNumber(variants.map((v) => v.final_price));
  const minBase = minNumber(variants.map((v) => v.base_price));

  const setProductCategoryInput = {
    category_id: 0,
    category_name: productMeta.category_name ?? productMeta.category ?? 'Uncategorized',
    parent_id: 0,
    visible: 1,
  };

  const setProductInput = {
    category_id: 0,
    visible: 1,
    products_title: productMeta.name ?? merged.product_name ?? 'Unnamed',
    products_internal_title: productMeta.supplier_sku ?? merged.product_id,
  };

  const setProductPriceTemplate = {
    product_price_id: 0,
    products_id: 0,
    qty: 1,
    qty_to: 999999,
    price: minFinal ?? 0,
    vendor_price: minBase ?? 0,
    size_id: 0,
    visible: '1',
  };

  return {
    json: {
      api_base: merged.api_base,
      customer_id: merged.customer_id,
      product_id: merged.product_id,
      product_name: merged.product_name,
      payload,
      setProductCategory_input: JSON.stringify(setProductCategoryInput, null, 2),
      setProduct_input: JSON.stringify(setProductInput, null, 2),
      setProductPrice_template: setProductPriceTemplate,
    },
  };
});

// Merges the category_id returned by setProductCategory into the setProduct_input.
// Falls back to category_id: 0 if OPS did not return one.

const categoryResult = $input.first().json ?? {};
const ctx = $node['Build OPS Inputs'].json;

const category_id = Number(categoryResult.category_id ?? 0);

const productInput = JSON.parse(ctx.setProduct_input);
productInput.category_id = category_id;

return [{
  json: {
    api_base: ctx.api_base,
    customer_id: ctx.customer_id,
    product_id: ctx.product_id,
    product_name: ctx.product_name,
    payload: ctx.payload,
    setProduct_input: JSON.stringify(productInput, null, 2),
    setProductPrice_template: ctx.setProductPrice_template,
  },
}];

// Builds one setProductSize_input item per variant so OPS: Set Product Size
// loops over all size/colour combinations for this product.
// Falls back to a single 'OS' (One Size) entry if the payload has no variants.

const setProductResult = $input.first().json ?? {};
const ctx = $node['Attach Category ID'].json;

const products_id = setProductResult.products_id ?? setProductResult.productsId;
if (!products_id) {
  throw new Error(`setProduct did not return products_id. Got: ${JSON.stringify(setProductResult)}`);
}

const payload = ctx.payload ?? {};
const variants = Array.isArray(payload.variants) ? payload.variants : [];

const sizeItems = variants.length
  ? variants.map((v) => ({
      size_name: v.size ?? v.size_name ?? 'OS',
      color_name: v.color ?? v.color_name ?? '',
      products_sku: v.sku ?? v.products_sku ?? ctx.product_id,
    }))
  : [{ size_name: 'OS', color_name: '', products_sku: ctx.product_id }];

return sizeItems.map((s) => ({
  json: {
    api_base: ctx.api_base,
    customer_id: ctx.customer_id,
    product_id: ctx.product_id,
    ops_product_id: String(products_id),
    setProductSize_input: JSON.stringify({
      product_size_id: 0,
      products_id: Number(products_id),
      size_name: s.size_name,
      color_name: s.color_name,
      products_sku: s.products_sku,
      visible: 1,
    }, null, 2),
  },
}));

// Combines the setProduct result with the pre-built price template.
// Reads context from Attach Category ID since OPS nodes only return GraphQL results.

const setProduct = $input.first().json ?? {};
const ctx = $node['Attach Category ID'].json;

const products_id = setProduct.products_id ?? setProduct.productsId;
if (!products_id) {
  throw new Error(`setProduct did not return products_id. Got: ${JSON.stringify(setProduct)}`);
}

const price = { ...(ctx.setProductPrice_template ?? {}) };
price.products_id = Number(products_id);

return [{
  json: {
    api_base: ctx.api_base,
    customer_id: ctx.customer_id,
    product_id: ctx.product_id,
    ops_product_id: String(products_id),
    setProductPrice_input: JSON.stringify(price, null, 2),
  },
}];

// Catches errors from any OPS node (Set Product Category, Set Product,
// Set Product Size, Set Product Price) and formats them for the error push log.

const err = $input.first().json ?? {};

return [{
  json: {
    api_base: err.api_base ?? $node['Build OPS Inputs']?.json?.api_base ?? '',
    customer_id: err.customer_id ?? $node['Build OPS Inputs']?.json?.customer_id ?? '',
    product_id: err.product_id ?? $node['Build OPS Inputs']?.json?.product_id ?? '',
    ops_product_id: err.ops_product_id ?? null,
    error_message: err.error?.message ?? err.message ?? JSON.stringify(err).substring(0, 500),
  },
}];

// STUB: OPS beta mutations (setAdditionalOption, setAdditionalOptionAttributes,
// setProductsAttributePrice) are not yet shipped.
// When they ship, replace this Code node with:
//   1. Split In Batches over options
//   2. OPS: setAdditionalOption (per option) → captures target_ops_option_id
//   3. Split In Batches over attributes
//   4. OPS: setAdditionalOptionAttributes → captures target_ops_attribute_id
//   5. OPS: setProductsAttributePrice → applies price
// For now: annotate each attribute with null target IDs and pass through.
const options = $input.all().map(i => i.json);
console.log('[STUB] ops-push options payload:', JSON.stringify(options));
return options.map(opt => ({
  json: {
    ...opt,
    _stub: true,
    target_ops_option_id: null,
    attributes: (opt.attributes || []).map(a => ({
      ...a,
      target_ops_attribute_id: null,
    })),
  }
}));

// Build push_mappings payload. Requires:
//  - upstream OPS: Set Product output has products_id
//  - Parse Params has product_id, customer_id
//  - Get Push Payload has product.supplier_sku and customer.ops_base_url
const params = $('Parse Params').item.json;
const payload = $('Get Push Payload').item.json;
const setProd = $('OPS: Set Product').item.json;
const opsOpts = $input.all().map(i => i.json);

const flatOptions = [];
for (const opt of opsOpts) {
  for (const a of (opt.attributes || [])) {
    flatOptions.push({
      source_master_option_id: opt.source_master_option_id,
      source_master_attribute_id: a.source_master_attribute_id,
      source_option_key: opt.option_key,
      source_attribute_key: a.source_attribute_key || a.title,
      target_ops_option_id: opt.target_ops_option_id,
      target_ops_attribute_id: a.target_ops_attribute_id,
      title: a.title,
      price: a.price,
      sort_order: a.sort_order,
    });
  }
}

return [{
  json: {
    source_system: payload.product?.source_system || 'sanmar',
    source_product_id: params.product_id,
    source_supplier_sku: payload.product?.supplier_sku || null,
    customer_id: params.customer_id,
    target_ops_base_url: payload.customer?.ops_base_url || '',
    target_ops_product_id: setProd.products_id,
    options: flatOptions,
  }
}];
